import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;
import com.google.gson.Gson;

public class GsonSerializeNullsTest {

  @Test
  public void testSerializeNulls_defaultConstructor() throws Exception {
    Gson gson = new Gson();
    // Default serializeNulls field is false as per DEFAULT_SERIALIZE_NULLS
    assertFalse(gson.serializeNulls());
  }

  @Test
  public void testSerializeNulls_reflectivelySetTrue() throws Exception {
    Gson gson = new Gson();
    Field serializeNullsField = Gson.class.getDeclaredField("serializeNulls");
    serializeNullsField.setAccessible(true);
    serializeNullsField.set(gson, true);
    assertTrue(gson.serializeNulls());
  }

  @Test
  public void testSerializeNulls_reflectivelySetFalse() throws Exception {
    Gson gson = new Gson();
    Field serializeNullsField = Gson.class.getDeclaredField("serializeNulls");
    serializeNullsField.setAccessible(true);
    serializeNullsField.set(gson, false);
    assertFalse(gson.serializeNulls());
  }
}
